1	import * as THREE from "three";
2	import { makeNoise3D, makeFbm } from "./noise.js";
3	
4	// ---- small color helpers (work in 0..255 int rgb) ----
5	function lerp(a, b, t) { return a + (b - a) * t; }
6	function mix(c1, c2, t) {
7	  return [
8	    lerp(c1[0], c2[0], t),
9	    lerp(c1[1], c2[1], t),
10	    lerp(c1[2], c2[2], t),
11	  ];
12	}
13	
14	// A dreamy lavender ocean world with a few GOLD islands. These are rendered as
15	// real metal (high metalness, low roughness) so they shimmer — the albedo here
16	// is gold's warm reflectance tint, richer/more saturated than a painted yellow.
17	// [height, rgb].
18	const LAND_STOPS = [
19	  [0.00, [214, 158, 58]],  // deep gold shore
20	  [0.30, [236, 180, 70]],  // gold
21	  [0.60, [248, 200, 96]],  // bright gold
22	  [0.85, [255, 222, 140]], // pale gold highland
23	  [1.00, [255, 240, 205]], // cream frost cap
24	];
25	
26	function rampLand(t) {
27	  for (let i = 0; i < LAND_STOPS.length - 1; i++) {
28	    const [h0, c0] = LAND_STOPS[i];
29	    const [h1, c1] = LAND_STOPS[i + 1];
30	    if (t <= h1) {
31	      const k = (t - h0) / (h1 - h0 || 1);
32	      return mix(c0, c1, Math.max(0, Math.min(1, k)));
33	    }
34	  }
35	  return LAND_STOPS[LAND_STOPS.length - 1][1];
36	}
37	
38	const DEEP = [64, 46, 130];      // deep saturated lavender
39	const SHALLOW = [112, 92, 178];   // mid lilac shallows
40	const SNOW = [232, 224, 244];     // cream-lilac frost
41	
42	// Shared landform constants so the texture bake and the elevation sampler below
43	// agree on exactly where land is.
44	const CONTINENT_FREQ = 1.5; // continent scale (lower = larger, calmer landforms)
45	const DEFAULT_SEA_LEVEL = 0.64;
46	
47	/**
48	 * Build a sampler that returns the planet's surface elevation (0..1) for a
49	 * lat/lon, using the *same* fbm field and frequency as the baked texture — so a
50	 * hotspot placed where `isLand` is true lands on visible gold, not the sea.
51	 */
52	export function createElevationSampler({ seed = 7 } = {}) {
53	  const noise = makeNoise3D(seed);
54	  const fbm = makeFbm(noise, { octaves: 4, lacunarity: 2.0, gain: 0.45 });
55	
56	  function elevationAt(latDeg, lonDeg) {
57	    const lat = (latDeg * Math.PI) / 180;
58	    const lon = (lonDeg * Math.PI) / 180;
59	    const cosLat = Math.cos(lat);
60	    const sx = cosLat * Math.cos(lon);
61	    const sy = Math.sin(lat);
62	    const sz = cosLat * Math.sin(lon);
63	    const h = fbm(sx * CONTINENT_FREQ, sy * CONTINENT_FREQ, sz * CONTINENT_FREQ);
64	    return h * 0.5 + 0.5;
65	  }
66	
67	  return {
68	    elevationAt,
69	    isLand(latDeg, lonDeg, seaLevel = DEFAULT_SEA_LEVEL) {
70	      return elevationAt(latDeg, lonDeg) >= seaLevel;
71	    },
72	    /**
73	     * Scan a coarse lat/lon grid (avoiding the icy poles) and return land spots
74	     * sorted by elevation, highest first — a good pick for an island that reads
75	     * clearly above the sea.
76	     */
77	    findLandSpots({ seaLevel = DEFAULT_SEA_LEVEL, latLimit = 60, step = 4 } = {}) {
78	      const spots = [];
79	      for (let lat = -latLimit; lat <= latLimit; lat += step) {
80	        for (let lon = -180; lon < 180; lon += step) {
81	          const h = elevationAt(lat, lon);
82	          if (h >= seaLevel) spots.push({ lat, lon, h });
83	        }
84	      }
85	      spots.sort((a, b) => b.h - a.h);
86	      return spots;
87	    },
88	  };
89	}
90	
91	/**
92	 * Bake equirectangular color / bump / roughness maps for the planet, plus a
93	 * separate cloud alpha map. Heavy-ish loop (~2M px) — run behind the loader.
94	 */
95	export function generatePlanetTextures({
96	  seed = 7,
97	  width = 2048,
98	  height = 1024,
99	  seaLevel = DEFAULT_SEA_LEVEL, // high → mostly ocean, just a few islands
100	} = {}) {
