1	import * as THREE from "three";
2	import { makeNoise3D, makeFbm } from "./noise.js";
3	
4	// A walkable island: a displaced plane with a radial falloff so the land rises
5	// out of a lavender sea and tapers back into it at the edges. Palette matches
6	// the planet — gold highlands, pale-gold shore, lavender shallows.
7	
8	// Colors as 0..1 rgb triples (vertex colors are linear-ish; kept soft).
9	const C_DEEP = [0.27, 0.21, 0.46];    // lavender lowland near water
10	const C_SHORE = [0.78, 0.66, 0.42];   // pale gold sand
11	const C_GOLD = [0.86, 0.66, 0.27];    // gold midland
12	const C_PEAK = [0.96, 0.86, 0.62];    // bright gold / cream highland
13	
14	function mix(a, b, t) {
15	  return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t, a[2] + (b[2] - a[2]) * t];
16	}
17	function ramp(t) {
18	  if (t < 0.18) return mix(C_DEEP, C_SHORE, t / 0.18);
19	  if (t < 0.5) return mix(C_SHORE, C_GOLD, (t - 0.18) / 0.32);
20	  return mix(C_GOLD, C_PEAK, Math.min(1, (t - 0.5) / 0.5));
21	}
22	
23	/**
24	 * Build the island terrain.
25	 *
26	 * @param {object} opts
27	 * @param {number} opts.size     world units across (square)
28	 * @param {number} opts.segments grid resolution
29	 * @param {number} opts.maxHeight peak elevation in world units
30	 * @param {number} opts.seed
31	 * @returns {{ mesh, water, size, maxHeight, heightAt(x,z), radius }}
32	 */
33	export function createTerrain({
34	  size = 200,
35	  segments = 220,
36	  maxHeight = 26,
37	  seed = 1337,
38	} = {}) {
39	  const noise = makeNoise3D(seed);
40	  const fbm = makeFbm(noise, { octaves: 5, lacunarity: 2.1, gain: 0.5 });
41	
42	  const half = size / 2;
43	  const seaLevel = 0; // world-space y of the surrounding water plane
44	
45	  // Raw elevation field in world units for a given world (x,z). Combines fbm
