1	import * as THREE from "three";
2	import { OrbitControls } from "three/addons/controls/OrbitControls.js";
3	import { RoomEnvironment } from "three/addons/environments/RoomEnvironment.js";
4	import { generatePlanetTextures, createElevationSampler } from "./planet.js";
5	import { makeAtmosphere } from "./atmosphere.js";
6	import { makeRing } from "./ring.js";
7	
8	const PLANET_RADIUS = 2;
9	const PLANET_SEED = 42;
10	const ISLAND_ANGLE = 0.32;      // angular radius of the landing region (radians)
11	
12	// Bird's-eye view: orbit the planet and click the pinned island to land on it.
13	export function createPlanetView(renderer, { onIslandClick } = {}) {
14	  const canvas = renderer.domElement;
15	
16	  const scene = new THREE.Scene();
17	  scene.background = new THREE.Color(0x07050f); // soft deep-violet void
18	
19	  // Image-based lighting so the gold islands have something to reflect.
20	  const pmrem = new THREE.PMREMGenerator(renderer);
21	  scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;
22	
23	  const camera = new THREE.PerspectiveCamera(
24	    45, window.innerWidth / window.innerHeight, 0.1, 1000
25	  );
26	  camera.position.set(0, 1.4, 6.5);
27	
28	  const controls = new OrbitControls(camera, canvas);
29	  controls.enableDamping = true;
30	  controls.dampingFactor = 0.06;
31	  controls.enablePan = false;
32	  controls.minDistance = 3.0;
33	  controls.maxDistance = 9.0;
34	  controls.rotateSpeed = 0.5;
35	  controls.autoRotate = false;
36	
37	  // ---------- lighting ----------
38	  const sun = new THREE.DirectionalLight(0xfff4e8, 1.8);
39	  sun.position.set(5, 2.5, 4);
40	  scene.add(sun);
41	  scene.add(new THREE.AmbientLight(0x6a5a92, 0.25));
42	  const rim = new THREE.DirectionalLight(0x8a7ab8, 0.6);
43	  rim.position.set(-5, -1, -4);
44	  scene.add(rim);
45	
46	  // ---------- starfield ----------
47	  scene.add(makeStars());
48	
49	  // ---------- planet ----------
50	  const planetGroup = new THREE.Group();
51	  scene.add(planetGroup);
52	  planetGroup.rotation.z = 0.42; // Saturn-like axial tilt so the ring reads
53	
54	  const { colorMap, bumpMap, roughnessMap, metalnessMap, cloudMap } =
55	    generatePlanetTextures({ seed: PLANET_SEED });
56	
57	  const planet = new THREE.Mesh(
58	    new THREE.SphereGeometry(PLANET_RADIUS, 128, 128),
59	    new THREE.MeshStandardMaterial({
60	      map: colorMap,
61	      bumpMap,
62	      bumpScale: 0.015,
63	      roughnessMap,
64	      roughness: 1.0,
65	      metalnessMap,
66	      metalness: 1.0,
67	      envMapIntensity: 0.3,
68	    })
69	  );
70	  planetGroup.add(planet);
71	
72	  const clouds = new THREE.Mesh(
73	    new THREE.SphereGeometry(PLANET_RADIUS * 1.012, 96, 96),
74	    new THREE.MeshStandardMaterial({
75	      map: cloudMap, transparent: true, depthWrite: false,
76	      color: 0xf2ecff, opacity: 0.4, roughness: 1.0,
77	    })
78	  );
79	  planetGroup.add(clouds);
80	
81	  planetGroup.add(makeAtmosphere(PLANET_RADIUS * 1.09, {
82	    color: new THREE.Color(0xc9a6ff), power: 2.2, intensity: 0.9,
83	  }));
84	
85	  planetGroup.add(makeRing(PLANET_RADIUS));
86	
87	  // ---------- the landable island ----------
88	  // Find a guaranteed patch of gold land, then anchor a marker on the texel
89	  // that paints it (geometry UV convention) so the pin sits on visible land.
90	  const sampler = createElevationSampler({ seed: PLANET_SEED });
91	  const spot = sampler.findLandSpots({ latLimit: 55, step: 3 })[0]
92	    || { lat: 20, lon: 40 };
93	  const islandLocalPos = latLonToSurface(spot.lat, spot.lon, PLANET_RADIUS);
94	  const islandLocalDir = islandLocalPos.clone().normalize();
95	
96	  // An invisible anchor on the surface we can read a world position from, and
97	  // a thin outline ring (NOT a glow) that fades in only on hover.
98	  const anchor = new THREE.Object3D();
99	  anchor.position.copy(islandLocalPos);
100	  anchor.quaternion.setFromUnitVectors(new THREE.Vector3(0, 1, 0), islandLocalDir);
101	  planet.add(anchor); // rides the planet so it tracks rotation
102	
103	  const ringRadius = PLANET_RADIUS * Math.sin(ISLAND_ANGLE);
104	  const ringDepth = PLANET_RADIUS * (1 - Math.cos(ISLAND_ANGLE));
105	  const outline = new THREE.Mesh(
106	    new THREE.RingGeometry(ringRadius * 0.94, ringRadius, 64),
107	    new THREE.MeshBasicMaterial({
108	      color: 0xfff4e8, transparent: true, opacity: 0,
109	      side: THREE.DoubleSide, depthTest: false, depthWrite: false,
110	    })
111	  );
112	  outline.rotation.x = -Math.PI / 2;       // lie flat on the surface
113	  outline.position.y = -ringDepth;          // drop to the sphere rim
114	  outline.renderOrder = 5;
115	  anchor.add(outline);
116	
117	  // ---------- HTML pin ----------
118	  const pin = document.getElementById("island-pin");
119	  const pinClick = () => { if (active) onIslandClick?.(); };
120	  const pinEnter = () => { hoverPin = true; };
121	  const pinLeave = () => { hoverPin = false; };
122	
123	  // ---------- interaction (only while this view is active) ----------
124	  const raycaster = new THREE.Raycaster();
125	  const pointer = new THREE.Vector2();
126	  const tmpWorld = new THREE.Vector3();
127	  const tmpLocal = new THREE.Vector3();
128	  let hoverRegion = false; // pointer is over the island on the globe
129	  let hoverPin = false;    // pointer is over the HTML pin
130	  let islandFaces = false; // island is on the near side, facing camera
131	  let pointerDownAt = null;
132	  let active = false;
133	
134	  // Is a screen point over the island region of the globe?
135	  function overIsland(event) {
136	    if (!islandFaces) return false;
137	    pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
138	    pointer.y = -(event.clientY / window.innerHeight) * 2 + 1;
139	    raycaster.setFromCamera(pointer, camera);
140	    const hit = raycaster.intersectObject(planet, false)[0];
141	    if (!hit) return false;
142	    // Compare the hit direction (in planet-local space) to the island centre.
143	    tmpLocal.copy(hit.point);
144	    planet.worldToLocal(tmpLocal).normalize();
145	    return tmpLocal.angleTo(islandLocalDir) < ISLAND_ANGLE;
146	  }
147	
148	  function onPointerMove(e) {
149	    const over = overIsland(e);
150	    if (over !== hoverRegion) {
151	      hoverRegion = over;
152	      canvas.style.cursor = over ? "pointer" : "default";
153	    }
154	  }
155	  function onPointerDown(e) { pointerDownAt = { x: e.clientX, y: e.clientY }; }
156	  function onPointerUp(e) {
157	    if (!pointerDownAt) return;
158	    const moved = Math.hypot(e.clientX - pointerDownAt.x, e.clientY - pointerDownAt.y);
