1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { createFirstPerson } from "./firstPerson.js";
4	import { createOverhead } from "./overhead.js";
5	import { FRAGMENTS, BUILDERS } from "./debris.js";
6	import { makeBeamTexture, makeIceBlock, makeIdSprite, genCheckpointId } from "./memoryProps.js";
7	
8	// The walkable island level — LEVEL 1 ("First Memories").
9	//
10	// A Diner-Dash-style loop, one memory at a time, driven by the REAL workflow
11	// typed into the ship's terminal:
12	//   walk up → terminal opens → `git add` (stage) → `git commit` (freeze in ice)
13	//   → Entire offers to link a checkpoint → press y → ship memory restores.
14	// When every memory is linked → run `entire checkpoint list` to review them all.
15	//
16	// PRESSURE: a single level countdown runs the whole time. Bank every memory
17	// before it hits zero, or the un-banked memories melt away and the run fails
18	// (press R to retry). One clock for the whole level — not per-memory.
19	//
20	// Teaching: a commit just freezes the change; linking a CHECKPOINT (the y/n
21	// offer Entire makes after a commit) is what restores it to the ship's memory.
22	
23	const INTERACT_DIST = 8;    // how close (XZ) to open a memory's terminal
24	const TOTAL_TIME = 45;      // seconds to recover & bank EVERY memory (tunable — scary-tight)
25	const MELT_DUR = 1.8;       // seconds the lost memories take to melt away
26	const LOW_TIME = 22;        // clock turns urgent (red, pulsing) under this many seconds
27	const CRIT_TIME = 8;        // clock goes CRITICAL (fast pulse) under this many seconds
28	const PANIC_TIME = 22;      // the SKY starts shifting toward panic-red under this many seconds
29	const MEMORY_COUNT = 3;     // calm tutorial: three memories
30	const BEAM_COLOR = 0xffd27a;
31	
32	// Sky panic palette — the whole world reddens as the clock runs out.
33	const SKY_CALM  = new THREE.Color(0x2a2350);  // lavender dusk (the resting sky/fog)
34	const SKY_PANIC = new THREE.Color(0x6e0f16);  // angry crimson
35	const FOG_PANIC = new THREE.Color(0x4a0a0e);  // deep blood fog closing in
36	const DOME_CALM = new THREE.Color(0x3a3168);
37	const DOME_PANIC = new THREE.Color(0x7a141c);
38	const SUN_CALM  = new THREE.Color(0xfff1dc);  // warm sun
39	const SUN_PANIC = new THREE.Color(0xff5a3c);  // hot red alarm light
40	
41	// Where each memory surfaces on the island (world XZ).
42	const PLACEMENTS = [
43	  { x: -34, z: -28 },
44	  { x: 40, z: -18 },
45	  { x: 28, z: 38 },
46	  { x: -30, z: 36 },
47	];
48	const DEV_LEVEL2_CHECKPOINTS = ["31f0cafe4d12", "7e11a2b09c44", "b0a7ded51a6e"];
49	
50	// What the terminal asks for at each stage of a memory's recovery.
51	const STEPS = {
52	  dormant:   { type: "command", cmd: "git add",    accept: ["git add"],    hint: "Stage the recovered memory" },
53	  recovered: { type: "command", cmd: "git commit", accept: ["git commit"], hint: "Commit it before the clock runs out" },
54	  frozen:    { type: "confirm", question: "Link this commit to a checkpoint?",
55	               hint: "Entire offers to capture the session behind this commit" },
56	};
57	// After every memory is linked, the player reviews them with this command.
58	const REVIEW_STEP = {
59	  type: "command", cmd: "entire checkpoint list", accept: ["entire checkpoint list"],
60	  hint: "All memories recovered — review what you've banked",
61	};
62	
63	function normalizeCmd(s) {
64	  return s.trim().toLowerCase().replace(/\s+/g, " ");
65	}
66	function cmdMatches(input, accepts) {
67	  const n = normalizeCmd(input);
68	  return accepts.some((a) => n === a || n.startsWith(a + " "));
69	}
