71	export function createIslandView(renderer, { onExit, onComplete, onNext, devStartLevel = 1 } = {}) {
72	  const canvas = renderer.domElement;
73	  const devLevel2 = devStartLevel === 2;
74	
75	  // ---------- scene & sky ----------
76	  const scene = new THREE.Scene();
77	  scene.background = new THREE.Color(0x2a2350); // lavender dusk sky
78	  scene.fog = new THREE.Fog(0x2a2350, 90, 320);
79	
80	  const camera = new THREE.PerspectiveCamera(
81	    62, window.innerWidth / window.innerHeight, 0.1, 2000
82	  );
83	
84	  // ---------- lighting (soft, warm sun in a lavender sky) ----------
85	  scene.add(new THREE.HemisphereLight(0xcdbcff, 0x3a2f5e, 0.7));
86	  const sun = new THREE.DirectionalLight(0xfff1dc, 1.5);
87	  sun.position.set(60, 90, 40);
88	  scene.add(sun);
89	  scene.add(new THREE.AmbientLight(0x6a5a92, 0.3));
90	
91	  const dome = new THREE.Mesh(
92	    new THREE.SphereGeometry(900, 32, 16),
93	    new THREE.MeshBasicMaterial({ color: 0x3a3168, side: THREE.BackSide, fog: false })
94	  );
95	  scene.add(dome);
96	
97	  // ---------- terrain ----------
98	  const terrain = createTerrain({ size: 200, segments: 220, maxHeight: 26, seed: 1337 });
99	  scene.add(terrain.mesh, terrain.water);
100	
101	  // ---------- memories ----------
102	  const beamTex = makeBeamTexture();
103	  const artifacts = [];
104	  FRAGMENTS.slice(0, MEMORY_COUNT).forEach((frag, idx) => {
105	    const place = PLACEMENTS[idx % PLACEMENTS.length];
106	    const groundY = terrain.heightAt(place.x, place.z);
107	    const anchor = new THREE.Group();
108	    anchor.position.set(place.x, groundY, place.z);
109	
110	    const model = BUILDERS[frag.kind]();
111	    model.scale.setScalar(14);
112	    model.position.y = 1.4;
113	    anchor.add(model);
114	
115	    // A tall light beam so the memory is findable from across the island.
116	    const beam = new THREE.Mesh(
117	      new THREE.CylinderGeometry(0.6, 0.6, 60, 12, 1, true),
118	      new THREE.MeshBasicMaterial({
119	        map: beamTex, color: BEAM_COLOR, transparent: true, opacity: 0.5,
120	        blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
121	        fog: false,
122	      })
123	    );
124	    beam.position.y = 30;
125	    anchor.add(beam);
126	
127	    const glow = new THREE.PointLight(BEAM_COLOR, 8, 40, 2);
128	    glow.position.y = 3;
129	    anchor.add(glow);
130	
131	    scene.add(anchor);
132	    artifacts.push({
133	      anchor, model, beam, glow, fragment: frag,
134	      state: "dormant",   // dormant → recovered (staged) → frozen (committed) → checkpointed
135	      ice: null, idSprite: null, core: null, id: null, iceY: 0,
136	      melting: false, meltT: 0,   // melt-away animation when the level times out
137	      bobOff: Math.random() * 10,
138	    });
139	  });
140	
141	  // ---------- first-person controller ----------
142	  const fp = createFirstPerson(camera, canvas, {
143	    heightAt: terrain.heightAt,
144	    radius: terrain.radius * 0.96,
145	    eyeHeight: 2.6,
146	    speed: 24,
147	  });
148	  scene.add(fp.controls.object);
149	
150	  // Bird's-eye map (M) — spot the memory beams from above, keep walking.
151	  const overhead = createOverhead(scene, terrain, camera);
152	  function setMap(on) {
153	    if (overhead.on === on) return;
154	    overhead.set(on);
155	    fp.setAlwaysMove(on);                       // arrows work without pointer lock
156	    scene.fog.near = on ? 500 : 90;             // don't fog the map out
157	    scene.fog.far = on ? 1400 : 320;
158	    crosshair?.classList.toggle("hidden", on || !fp.isLocked);
159	  }
160	
161	  // ---------- HUD elements ----------
162	  const promptEl = document.getElementById("fp-prompt");
163	  const controlsEl = document.getElementById("fp-controls");
164	  const crosshair = document.getElementById("crosshair");
165	  const islandHud = document.getElementById("island-hud");
166	  const tutorialEl = document.getElementById("tutorial");
167	  const actionBar = document.getElementById("action-bar");
168	  const actionBarFill = document.getElementById("action-bar-fill");
169	  const shipMeter = document.getElementById("ship-meter");
170	  const shipMeterFill = document.getElementById("ship-meter-fill");
171	  const shipMeterPct = document.getElementById("ship-meter-pct");
172	  const ckptCard = document.getElementById("ckpt-card");
173	  const ccId = document.getElementById("cc-id");
174	  const ccSummary = document.getElementById("cc-summary");
175	  const ccAttrFill = document.getElementById("cc-attr-fill");
176	  const ccAttrText = document.getElementById("cc-attr-text");
177	  const termEl = document.getElementById("terminal");
178	  const termHint = document.getElementById("term-hint");
179	  const termInput = document.getElementById("term-input");
180	  const termList = document.getElementById("term-list");
181	  const termMsg = document.getElementById("term-msg");
182	  const termCta = document.getElementById("term-cta");
183	  const countdownEl = document.getElementById("countdown");
184	  const countdownTime = document.getElementById("countdown-time");
185	  const levelFail = document.getElementById("level-fail");
186	  const briefingEl = document.getElementById("briefing");
187	  const briefingStartBtn = document.getElementById("briefing-start");
188	  const devLevelBadge = document.getElementById("dev-level-badge");
189	  const fpShared = document.getElementById("fp-shared");
190	
191	  let target = null;            // nearest memory in range
192	  let active = false;           // is this view being shown?
193	  let promptText = null;
194	  let controlsLocked = null;
195	  const taught = new Set();
196	  let tutorialTimer = null;
197	  let cardTimer = null;
198	  let msgTimer = null;
199	
200	  // Terminal state
201	  let terminalOpen = false;
202	  let termTarget = null;        // the memory whose terminal is open
203	  let buffer = "";              // what the player has typed
204	  let dismissedMemory = null;   // memory the player Esc'd out of (until they leave)
205	  let reviewMode = false;       // all linked → review with `entire checkpoint list`
206	  let listShown = false;        // the list has been printed
207	
208	  // Level countdown — the single source of pressure for the whole run.
209	  let timeLeft = TOTAL_TIME;
210	  let timerRunning = false;
211	  let failed = false;
212	  let started = false;          // briefing dismissed → movement + clock go live
213	
214	  const checkpointedCount = () =>
215	    artifacts.filter((a) => a.state === "checkpointed").length;
216	  const allLinked = () => checkpointedCount() >= artifacts.length;
217	
218	  // ---------- HUD helpers ----------
219	  function setPrompt(text) {
220	    if (!promptEl || text === promptText) return;
221	    promptText = text;
222	    if (text) { promptEl.textContent = text; promptEl.classList.remove("hidden"); }
223	    else promptEl.classList.add("hidden");
224	  }
225	  function hideActionBar() { actionBar.classList.add("hidden"); }
226	
227	  // ---------- level countdown ----------
228	  function fmtTime(s) {
229	    s = Math.max(0, Math.ceil(s));
230	    return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
231	  }
232	  function updateClock() {
233	    if (countdownTime) countdownTime.textContent = fmtTime(timeLeft);
234	    countdownEl?.classList.toggle("is-low", timerRunning && timeLeft <= LOW_TIME);
235	    countdownEl?.classList.toggle("is-critical", timerRunning && timeLeft <= CRIT_TIME);
236	  }
237	
238	  // How hard the sky is panicking right now: 0 = calm lavender, 1 = full crimson throb.
239	  function panicFactor() {
240	    if (failed) return 1;                         // hold the dread behind the fail screen
241	    if (!timerRunning || timeLeft > PANIC_TIME) return 0;
242	    let p = (PANIC_TIME - timeLeft) / PANIC_TIME; // 0 at PANIC_TIME → 1 at 0:00
243	    p *= p;                                        // eased: barely there early, harsh late
244	    if (timeLeft <= CRIT_TIME) {                   // throb once it's critical
245	      const throb = 0.5 + 0.5 * Math.sin(performance.now() / 85);
246	      p += 0.14 * throb;
247	    }
248	    return Math.min(1, p);
249	  }
250	  function applyPanicSky() {
251	    const p = panicFactor();
252	    scene.background.copy(SKY_CALM).lerp(SKY_PANIC, p);
253	    scene.fog.color.copy(SKY_CALM).lerp(FOG_PANIC, p);
254	    dome.material.color.copy(DOME_CALM).lerp(DOME_PANIC, p);
255	    sun.color.copy(SUN_CALM).lerp(SUN_PANIC, p * 0.85);
256	  }
257	  function failLevel() {
258	    if (failed) return;
259	    failed = true;
260	    timerRunning = false;
261	    setMap(false);
262	    closeTerminal(false);
263	    fp.detach();                  // freeze the player behind the fail screen
264	    // Un-banked memories always melt; if they ran out the clock on the final
265	    // `entire checkpoint list` (all banked, not yet reviewed), the whole run melts.
266	    for (const a of artifacts) {
267	      if (reviewMode || a.state !== "checkpointed") { a.melting = true; a.meltT = MELT_DUR; }
268	    }
269	    countdownEl?.classList.remove("is-low", "is-critical");
270	    tutorialEl?.classList.add("hidden");
271	    levelFail?.classList.remove("hidden");
272	  }
273	  function resetLevel() {
274	    failed = false;
275	    levelFail?.classList.add("hidden");
276	    if (active) fp.attach();      // movement resumes for the new run
277	    for (const a of artifacts) {
278	      if (a.ice) { a.anchor.remove(a.ice); a.ice = null; }
279	      if (a.idSprite) { a.anchor.remove(a.idSprite); a.idSprite = null; }
280	      if (a.core) { a.anchor.remove(a.core); a.core = null; }
281	      a.state = "dormant";
282	      a.id = null;
283	      a.melting = false; a.meltT = 0;
284	      a.model.position.y = 1.4;
285	      setModelOpacity(a.model, 1);
286	    }
287	    reviewMode = false;
288	    listShown = false;
289	    dismissedMemory = null;
290	    shipMeter?.classList.remove("is-full");
291	    setPower();
292	    timeLeft = TOTAL_TIME;
293	    timerRunning = true;
294	    updateClock();
295	    showTutorial("New attempt — bank all three memories before the clock hits zero.", 4500);
296	  }
297	
298	  // Dev-only Level 2 entry point: pretend Level 1 has already been completed so
299	  // the next level can be built/tested without replaying the timed tutorial.
300	  function seedLevel2DevState() {
301	    started = true;
302	    failed = false;
303	    timerRunning = false;
304	    reviewMode = false;
305	    listShown = true;
306	    dismissedMemory = null;
307	    levelFail?.classList.add("hidden");
308	    briefingEl?.classList.add("hidden");
309	    termEl?.classList.add("hidden");
310	
311	    artifacts.forEach((a, idx) => {
312	      a.state = "checkpointed";
313	      a.id = DEV_LEVEL2_CHECKPOINTS[idx % DEV_LEVEL2_CHECKPOINTS.length];
314	      a.melting = false;
315	      a.meltT = 0;
316	      a.model.position.y = 1.4;
317	      setModelOpacity(a.model, 1);
318	
319	      if (!a.ice) {
320	        const ice = makeIceBlock();
321	        ice.position.y = a.model.position.y + 0.6;
322	        a.iceY = ice.position.y;
323	        a.anchor.add(ice);
324	        a.ice = ice;
325	      }
326	      a.ice.material.opacity = 0.62;
327	      a.ice.material.emissive.setHex(0x2a6c8a);
328	      a.ice.material.emissiveIntensity = 1.1;
329	
330	      if (!a.core) {
331	        const core = new THREE.PointLight(0x8fe3ff, 6, 26, 2);
332	        core.position.copy(a.ice.position);
333	        a.anchor.add(core);
334	        a.core = core;
335	      }
336	      if (!a.idSprite) {
337	        const spr = makeIdSprite(a.id);
338	        spr.position.y = a.iceY + 5;
339	        a.anchor.add(spr);
340	        a.idSprite = spr;
341	      }
342	
343	      a.beam.visible = false;
344	      a.glow.visible = false;
345	    });
346	
347	    shipMeter?.classList.add("is-full");
348	    setPower();
349	    updateClock();
350	    applyPanicSky();
351	  }
352	
353	  // Landing briefing — the level is frozen (no clock, no movement) until START.
354	  function showBriefing() {
355	    timerRunning = false;
356	    fp.detach();
357	    tutorialEl?.classList.add("hidden");
358	    briefingEl?.classList.remove("hidden");
359	  }
360	  function startLevel() {
361	    if (started) return;
362	    started = true;
363	    briefingEl?.classList.add("hidden");
364	    fp.attach();
365	    timeLeft = TOTAL_TIME;
366	    timerRunning = true;
367	    updateClock();
368	    showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
369	  }
