532	  function showCheckpointList() {
533	    listShown = true;
534	    timerRunning = false;            // the run is complete — NOW the clock stops
535	    countdownEl?.classList.remove("is-low", "is-critical");
536	    if (termList) {
537	      termList.innerHTML = artifacts.map((a) =>
538	        `<div class="term-list-row"><span class="tl-id">` +
539	        `<span class="tl-key">Entire-Checkpoint:</span> ${a.id}</span>` +
540	        `<span class="tl-title">recovered: ${a.fragment.title}</span></div>`
541	      ).join("");
