678	    hideActionBar();
679	    if (overhead.on) { setPrompt("Bird's-eye view — ↑↓←→ to move · M to return"); return; }
680	    if (devLevel2) {
681	      setPrompt(fp.isLocked ? "Level 2 dev start — press B to return to orbit" : "Click to look around");
682	      return;
683	    }
