689	  // ---------- per-frame ----------
690	  function update(dt, t) {
691	    fp.update(dt);
692	
693	    // Level countdown — one clock for the whole run.
694	    if (active && timerRunning && !failed) {
695	      timeLeft = Math.max(0, timeLeft - dt);
696	      updateClock();
697	      if (timeLeft <= 0) failLevel();
698	    }
699	    applyPanicSky();   // the sky reacts to the clock every frame
700	
701	    // Nearest memory within reach (ignoring height).
702	    let nearest = null, nd = Infinity;
703	    for (const a of artifacts) {
704	      const dx = camera.position.x - a.anchor.position.x;
705	      const dz = camera.position.z - a.anchor.position.z;
706	      const d = Math.hypot(dx, dz);
707	      if (d < nd) { nd = d; nearest = a; }
708	    }
709	    target = nd <= INTERACT_DIST ? nearest : null;
710	
711	    // Auto open/close the ship's terminal as you reach a memory.
712	    // (In review mode the terminal is driven manually, so leave it alone.)
713	    if (active && started && !reviewMode && !failed && !devLevel2) {
714	      if (dismissedMemory && target !== dismissedMemory) dismissedMemory = null;
715	      const canOpen = target && target.state !== "checkpointed" && target !== dismissedMemory;
716	      if (canOpen && !terminalOpen) openTerminal(target);
717	      else if (!canOpen && terminalOpen) closeTerminal(false);
718	    }
719	
720	    for (const a of artifacts) {
721	      // Melting away after a time-out — sink and fade, then disappear.
722	      if (a.melting) {
723	        a.meltT = Math.max(0, a.meltT - dt);
724	        const k = a.meltT / MELT_DUR;
725	        setModelOpacity(a.model, k);
726	        a.model.position.y -= dt * 2.4;
727	        if (a.ice) a.ice.material.opacity = 0.62 * k;
728	        a.beam.visible = false;
729	        a.glow.visible = false;
730	        continue;
731	      }
732	
733	      const encased = a.state === "frozen" || a.state === "checkpointed";
734	
735	      // Idle spin/bob until the memory is encased in ice.
736	      if (!encased) {
737	        a.model.rotation.y += dt * 0.6;
738	        a.model.position.y = 1.4 + Math.sin((t + a.bobOff) * 1.5) * 0.4;
739	        setModelOpacity(a.model, 1);
740	      }
741	
742	      // Beam + glow: bright while findable, gone once frozen.
743	      const lit = a.state === "dormant" || a.state === "recovered";
744	      let o = 0;
745	      if (a.state === "dormant") o = 0.4 + Math.sin(t * 2) * 0.12;
746	      else if (a.state === "recovered") o = 0.22;
747	      a.beam.material.opacity = o;
748	      a.beam.visible = o > 0.01;
749	      a.glow.visible = lit;
750	    }
751	
752	    overhead.update(t);
753	    if (terminalOpen) renderTerminal(); // reflect fade-driven state changes
754	    if (active) refreshHud();
755	  }
756	
757	  // ---------- lifecycle ----------
758	  function enter() {
759	    active = true;
760	    fp.groundAt(0, terrain.radius * 0.75);
761	    camera.lookAt(0, terrain.heightAt(0, 0) + 6, 0);
762	    canvas.addEventListener("click", onCanvasClick);
763	    window.addEventListener("keydown", onKeyDown);
764	    islandHud?.classList.remove("hidden");
765	    islandHud?.classList.toggle("is-level2-dev", devLevel2);
766	    devLevelBadge?.classList.toggle("hidden", !devLevel2);
767	    fpShared?.classList.remove("hidden");
768	    setControls(false);
769	    crosshair?.classList.add("hidden");
770	    setPower();
771	    if (devLevel2) {
772	      seedLevel2DevState();
773	      fp.attach();
774	      showTutorial("Level 2 dev mode — Level 1 checkpoints are preloaded.", 0);
775	    } else if (!started) {          // fresh landing — read the briefing, then START
776	      showBriefing();
777	    } else if (listShown) {         // truly done — the list has been run
778	      fp.attach();
779	      timerRunning = false;
780	      showTutorial("Memory restored — press Enter to answer the new signal, or B for orbit.", 0);
781	    } else if (failed) {
782	      resetLevel();                 // came back after a wipe → fresh run
783	    } else {
784	      fp.attach();
785	      timerRunning = true;          // resume the level clock
786	      if (reviewMode) {             // resume the timed final review
787	        openTerminal(artifacts[0]); // termTarget unused in review; reopens the prompt
788	        showTutorial("Type `entire checkpoint list` before the clock hits 0:00!", 0);
789	      } else {
790	        showTutorial("Memories are surfacing — the clock's short. Bank all three before 0:00!", 6500);
791	      }
792	    }
793	    updateClock();
794	    applyPanicSky();   // start on the right sky (calm unless we resumed low on time)
795	  }
796	  function exit() {
797	    active = false;
798	    timerRunning = false;           // pause the clock while in orbit
799	    setMap(false);
800	    closeTerminal(false);
801	    fp.unlock();
802	    fp.detach();
803	    canvas.removeEventListener("click", onCanvasClick);
804	    window.removeEventListener("keydown", onKeyDown);
805	    setPrompt(null);
806	    hideControls();
807	    hideActionBar();
808	    tutorialEl?.classList.add("hidden");
809	    ckptCard?.classList.add("hidden");
810	    termEl?.classList.add("hidden");
811	    levelFail?.classList.add("hidden");
812	    briefingEl?.classList.add("hidden");
813	    islandHud?.classList.add("hidden");
814	    islandHud?.classList.remove("is-level2-dev");
815	    devLevelBadge?.classList.add("hidden");
816	    fpShared?.classList.add("hidden");
817	    crosshair?.classList.add("hidden");
818	  }
819	  function resize() {
820	    camera.aspect = window.innerWidth / window.innerHeight;
821	    camera.updateProjectionMatrix();
822	    overhead.resize();
823	  }
824	
825	  return {
826	    scene,
