194	// ---------- prop builders: what the drones improvise them into ----------
195	function buildPlasmaRing() {
196	  const g = new THREE.Group();
197	  const base = new THREE.Mesh(new THREE.CylinderGeometry(1.2, 1.5, 0.7, 10), SCORCH());
198	  base.position.y = 0.35;
199	  const ring = new THREE.Mesh(
200	    new THREE.TorusGeometry(1.8, 0.3, 12, 36),
201	    new THREE.MeshStandardMaterial({ color: 0x6b4a16, emissive: 0xffb86b, emissiveIntensity: 1.4, roughness: 0.4 })
202	  );
203	  ring.position.y = 3.4;
204	  g.add(base, ring);
205	  g.userData.anim = { type: "ring", ring };
206	  return g;
207	}
208	function buildStarDome() {
209	  const g = new THREE.Group();
210	  const ped = new THREE.Mesh(new THREE.CylinderGeometry(0.9, 1.2, 1.2, 8), SCORCH());
211	  ped.position.y = 0.6;
212	  const stars = new THREE.BufferGeometry();
213	  const pts = new Float32Array(120 * 3);
214	  for (let i = 0; i < 120; i++) {
215	    // random points in a dome above the pedestal
216	    const r = 1.2 + Math.random() * 1.4;
217	    const th = Math.random() * Math.PI * 2;
218	    const ph = Math.random() * Math.PI * 0.5;
219	    pts[i * 3] = Math.cos(th) * Math.sin(ph) * r;
220	    pts[i * 3 + 1] = 3.2 + Math.cos(ph) * r * 0.9;
221	    pts[i * 3 + 2] = Math.sin(th) * Math.sin(ph) * r;
222	  }
223	  stars.setAttribute("position", new THREE.BufferAttribute(pts, 3));
224	  const field = new THREE.Points(stars, new THREE.PointsMaterial({
225	    color: 0xbfe9ff, size: 0.16, transparent: true, opacity: 0.95,
226	    blending: THREE.AdditiveBlending, depthWrite: false,
227	  }));
228	  const orbit = new THREE.Mesh(
