803	    if (!reviewSite || explained) return;
804	    explained = true;
805	    const s = reviewSite;
806	    if (termList) {
807	      termList.innerHTML =
808	        `<div class="term-list-row"><span class="tl-key tl-exp-key">checkpoint</span>` +
809	        `<span class="tl-title">${s.sys.ckpt}</span></div>` +
810	        s.sys.card.map(([k, v]) =>
811	          `<div class="term-list-row"><span class="tl-key tl-exp-key">${k}</span>` +
812	          `<span class="tl-title">${v}</span></div>`
813	        ).join("");
814	      termList.classList.remove("hidden");
815	    }
816	    flashTerminal(`explained ${s.sys.ckpt} — ${s.sys.name.toLowerCase()} is now a ${s.sys.became}`, true);
817	    teachOnce("explained",
818	      "That's the story behind the checkpoint — work you didn't watch is never a mystery. If it's good, add it to the ship.", 8000);
819	    renderTerminal();
820	  }
821	
822	  // ---------- ADD TO SHIP ----------
823	  function addToShip() {
824	    if (!reviewSite || !explained) return;
825	    const s = reviewSite;
826	    s.state = "added";
827	    s.meltT = MELT_DUR;                 // the seal melts; the upgrade wakes up
828	    const anim = s.upgradeModel.userData.anim;
829	    if (anim?.type === "spire") anim.beam.visible = true;
830	    updateSystems();
831	    if (allAdded()) {
832	      // The fifth accept doesn't close the terminal — the finish line is the
833	      // next command at the prompt you're already at, like the real CLI.
834	      termMode = "report";
835	      reviewSite = null;
836	      explained = false;
837	      buffer = "";
838	      termList?.classList.add("hidden");
839	      flashTerminal("all five systems online", true);
840	      showTutorial("Every system accounted for — send the day's report: type `entire dispatch`.", 0);
841	      renderTerminal();
842	    } else {
843	      closeTerminal(false);
844	      showTutorial(`${s.sys.name} online (${addedCount()} / ${sites.length}).`, 5000);
845	    }
846	  }
847	  // The ADD TO SHIP button (terminal CTA is re-rendered, so delegate the click).
848	  termCta?.addEventListener("click", (e) => {
849	    if (!active) return;
850	    if (e.target?.id === "db-add-btn") addToShip();
851	  });
852	
853	  // ---------- the finish line: entire dispatch ----------
854	  // "Generate a dispatch summarizing recent agent work" — five drones just
855	  // worked; the report writes itself from their checkpoints.
856	  function sendDispatch() {
857	    reportSent = true;
858	    timerRunning = false;
859	    countdownEl?.classList.remove("is-low", "is-critical");
860	    if (termList) {
861	      termList.innerHTML =
862	        `<div class="term-list-row"><span class="tl-key tl-exp-key">DISPATCH</span>` +
863	        `<span class="tl-title">drone bay — day report</span></div>` +
864	        sites.map((s) =>
865	          `<div class="term-list-row"><span class="tl-key tl-exp-key">·</span>` +
866	          `<span class="tl-title">${s.sys.name.toLowerCase()} → ${s.sys.became} (${s.sys.ckpt.slice(0, 6)}…)</span></div>`
867	        ).join("") +
868	        `<div class="term-list-row"><span class="tl-key tl-exp-key">filed</span>` +
869	        `<span class="tl-title">from 5 checkpoints · crew: 1 human, 5 subagents</span></div>`;
870	      termList.classList.remove("hidden");
871	    }
872	    flashTerminal("dispatch sent — look how much got done without you", true);
873	    renderTerminal();
874	    if (winSub) {
875	      winSub.textContent = "five jobs in parallel — the report wrote itself";
876	    }
877	    winTimer = setTimeout(() => {
878	      closeTerminal(false);
879	      tutorialEl?.classList.add("hidden");
880	      winEl?.classList.remove("hidden");
881	    }, 4000);
882	    onComplete?.();               // Level 2 cleared — opens the launch window
883	  }
884	  function submitCommand() {
885	    const n = normalizeCmd(buffer);
886	    buffer = "";
887	    if (!n) { renderTerminal(); return; }
888	    if (/^entire dispatch$/.test(n)) { sendDispatch(); return; }
889	    if (/^entire (checkpoint|cp) list$/.test(n)) {
890	      // L1's command still works — the raw log, then the nudge to report.
891	      if (termList) {
892	        termList.innerHTML = sites.map((s) =>
893	          `<div class="term-list-row"><span class="tl-id tl-id-short">${s.sys.ckpt}</span>` +
894	          `<span class="tl-title">subagent fix: ${s.sys.name.toLowerCase()} → ${s.sys.became}</span></div>`
895	        ).join("");
896	        termList.classList.remove("hidden");
897	      }
898	      flashTerminal("the raw log — now turn it into the day's report:  entire dispatch", true);
899	      renderTerminal();
900	      return;
901	    }
902	    flashTerminal("command not recognized — try:  entire dispatch", false);
903	    renderTerminal();
904	  }
905	
906	  // ---------- input ----------
907	  function onCanvasClick() {
908	    if (!started || failed) return;
909	    if (active && !fp.isLocked && !terminalOpen) fp.lock();
910	  }
911	  function onKeyDown(e) {
912	    if (!active) return;
913	
914	    // Briefing is up — Enter/Space begins the run, nothing else.
915	    if (!started) {
916	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
917	      return;
918	    }
919	
920	    // The clock ran out — only R (retry) does anything.
921	    if (failed) {
922	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
923	      return;
924	    }
925	
926	    // While the terminal is open, all keys feed it.
927	    if (terminalOpen) {
928	      if (e.code === "Escape") { closeTerminal(true); e.preventDefault(); return; }
929	      if (termMode === "review") {
930	        if (!explained && e.code === "Enter") { runExplain(); e.preventDefault(); return; }
931	        if (explained && (e.key === "y" || e.key === "Y")) { addToShip(); e.preventDefault(); return; }
932	        e.preventDefault();
933	        return;
934	      }
935	      // report mode — type the dispatch command (the finish line)
936	      if (reportSent) { e.preventDefault(); return; }  // only Esc closes the report
937	      if (e.code === "Enter") { submitCommand(); e.preventDefault(); return; }
938	      if (e.code === "Backspace") { buffer = buffer.slice(0, -1); renderTerminal(); e.preventDefault(); return; }
939	      if (e.key && e.key.length === 1 && !e.ctrlKey && !e.metaKey && !e.altKey) {
940	        buffer += e.key;
941	        renderTerminal();
942	        e.preventDefault();
943	      }
944	      return;
945	    }
946	
947	    // Walking around.
948	    // Level cleared → Enter boards the ship; failure never advances (R only).
949	    if (reportSent && e.code === "Enter") { onNext?.(); e.preventDefault(); return; }
950	    if (e.code === "KeyE" && nearSite?.state === "broken") { assignDrone(nearSite); e.preventDefault(); return; }
951	    if (e.code === "KeyM") { setMap(!overhead.on); e.preventDefault(); return; }
952	    if (e.code === "Escape" && fp.isLocked) fp.unlock();
953	    if (e.code === "KeyB") onExit?.();
954	  }
955	  fp.controls.addEventListener("lock", () => crosshair?.classList.remove("hidden"));
956	  fp.controls.addEventListener("unlock", () => crosshair?.classList.add("hidden"));
957	
958	  // ---------- HUD per-frame ----------
959	  let nearSite = null;
960	  let nearConsole = false;
961	
962	  function refreshHud() {
963	    if (!started || terminalOpen) {
964	      setPrompt(null);
965	      hideControls();
966	      return;
967	    }
968	    setControls(fp.isLocked);
969	    if (overhead.on) { setPrompt("Bird's-eye view — ↑↓←→ to move · M to return"); return; }
970	    if (!fp.isLocked) { setPrompt("Click to look around"); return; }
971	    if (reportSent) { setPrompt("The day is dispatched — press Enter to board the ship"); return; }
972	    if (nearSite) {
973	      if (nearSite.state === "broken") setPrompt(`${nearSite.sys.name} is down — press E to send a subagent`);
974	      else if (nearSite.state === "working") setPrompt("Subagent at work — you're free, go assign another");
975	      else if (nearSite.state === "added" && !allAdded()) setPrompt(`${nearSite.sys.became} online — accepted into the ship`);
976	      return;
977	    }
978	    if (allAdded()) { setPrompt("Walk to any online system — send the day's report: `entire dispatch`"); return; }
979	    if (sites.some((s) => s.state === "sealed")) {
980	      setPrompt("An ice-blue beam means finished work — go review it");
981	      return;
982	    }
983	    if (sites.some((s) => s.state === "broken")) {
984	      setPrompt("Amber beams are broken systems — send the subagents (E)");
985	      return;
986	    }
987	    setPrompt("The fleet is working — wait for an ice-blue beam, then go review");
988	  }
989	
990	  // ---------- per-frame ----------
991	  function update(dt, t) {
992	    fp.update(dt);
993	
994	    // Level countdown — one clock for the whole run.
995	    if (active && timerRunning && !failed && !reportSent) {
996	      timeLeft = Math.max(0, timeLeft - dt);
997	      updateClock();
998	      if (timeLeft <= 0) failLevel();
999	    }
1000	    applyPanicSky();
1001	
1002	    // Drones fly, work, and head home.
1003	    for (let i = 0; i < drones.length; i++) {
1004	      const d = drones[i];
1005	      const beam = workBeams[i];
1006	      if (d.state === "bay") {
1007	        d.model.position.y = d.home.y + Math.sin((t + d.bobOff) * 2) * 0.15;
1008	        d.model.userData.ring.rotation.z += dt * 1.2;
1009	      } else if (d.state === "flying" || d.state === "returning") {
1010	        d.t += dt;
1011	        const k = Math.min(1, d.t / d.dur);
1012	        const ease = k * k * (3 - 2 * k);
1013	        d.model.position.lerpVectors(d.from, d.to, ease);
1014	        d.model.position.y += Math.sin(k * Math.PI) * 3;   // arc over the island
1015	        d.model.userData.ring.rotation.z += dt * 6;
1016	        if (k >= 1) {
1017	          if (d.state === "flying") d.state = "working";
1018	          else { d.state = "bay"; d.model.position.copy(d.home); }
1019	        }
1020	      } else if (d.state === "working") {
1021	        const s = d.site;
1022	        d.model.position.set(
1023	          s.anchor.position.x + Math.cos(t * 1.4) * 1.2,
1024	          s.anchor.position.y + 6.5 + Math.sin(t * 2.2) * 0.4,
1025	          s.anchor.position.z + Math.sin(t * 1.4) * 1.2
1026	        );
1027	        d.model.userData.ring.rotation.z += dt * 9;
1028	        beam.visible = true;
1029	        beam.position.set(d.model.position.x, d.model.position.y - 3.2, d.model.position.z);
1030	        beam.material.opacity = 0.35 + Math.sin(t * 11) * 0.2;
1031	
1032	        // The actual work happens whether you watch or not.
1033	        if (active && started && !failed) {
1034	          s.workT += dt;
1035	          if (s.workT >= WORK_TIME) {
1036	            sealSite(s);
1037	            beam.visible = false;
1038	            d.state = "returning";
1039	            d.site = null;
1040	            d.from.copy(d.model.position);
1041	            d.to.copy(d.home);
1042	            d.t = 0;
1043	            d.dur = Math.max(1, d.from.distanceTo(d.to) / DRONE_SPEED);
1044	          }
1045	        }
1046	      }
1047	    }
1048	
1049	    // Sites: status beams, warning blinks, seals, and live upgrades.
1050	    for (const s of sites) {
1051	      if (s.state === "broken") {
1052	        s.beam.material.color.setHex(0xff8a5c);
1053	        s.beam.material.opacity = 0.24 + Math.sin(t * 1.6 + s.idx) * 0.08;
1054	        s.beam.visible = true;
1055	        const warn = s.brokenModel.userData.warn;
1056	        if (warn) warn.material.emissiveIntensity = Math.sin(t * 5 + s.idx) > 0 ? 1.8 : 0.2;
1057	      } else if (s.state === "working") {
1058	        s.beam.material.color.setHex(0x6fe3ff);
1059	        s.beam.material.opacity = 0.4 + Math.sin(t * 6) * 0.18;
1060	        s.beam.visible = true;
1061	      } else if (s.state === "sealed") {
1062	        s.beam.material.color.setHex(0x8fe3ff);
1063	        s.beam.material.opacity = 0.42;
1064	        s.beam.visible = true;
1065	      } else {
1066	        s.beam.visible = false;       // added — the upgrade itself is the landmark
1067	        if (s.meltT > 0) {            // the checkpoint seal melts away
1068	          s.meltT = Math.max(0, s.meltT - dt);
1069	          s.ice.material.opacity = 0.62 * (s.meltT / MELT_DUR);
1070	          if (s.meltT <= 0) s.ice.visible = false;
1071	        }
1072	        // The improvised upgrades live a little.
1073	        const anim = s.upgradeModel.userData.anim;
1074	        if (anim?.type === "ring") {
1075	          anim.ring.rotation.y += dt * 0.8;
1076	          anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
1077	        } else if (anim?.type === "dome") {
1078	          anim.field.rotation.y += dt * 0.25;
1079	          anim.orbit.rotation.z += dt * 0.6;
1080	        } else if (anim?.type === "skid") {
1081	          anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
1082	        }
1083	      }
1084	    }
1085	
1086	    // Proximity: nearest site, and the ship console.
1087	    nearSite = null;
1088	    let nd = Infinity;
1089	    for (const s of sites) {
1090	      const d = Math.hypot(
1091	        camera.position.x - s.anchor.position.x,
1092	        camera.position.z - s.anchor.position.z
1093	      );
1094	      if (d < nd) { nd = d; if (d <= INTERACT_DIST) nearSite = s; }
1095	    }
1096	    nearConsole = Math.hypot(
1097	      camera.position.x - CONSOLE_POS.x, camera.position.z - CONSOLE_POS.z
1098	    ) <= CONSOLE_DIST;
1099	    consoleGlow.intensity = allAdded() && !reportSent ? 8 + Math.sin(t * 4) * 3 : 5;
1100	
1101	    // Terminals open themselves at the right places, like Level 1. After the
1102	    // fifth accept the report prompt is already open in place; if the player
1103	    // wanders off, any ONLINE system (or the bay console) reopens it.
1104	    const atReportSpot = nearConsole || nearSite?.state === "added";
1105	    if (active && started && !failed) {
1106	      if (dismissedSite && nearSite !== dismissedSite) dismissedSite = null;
1107	      if (reportDismissed && !atReportSpot) reportDismissed = false;
1108	      if (!terminalOpen) {
1109	        if (nearSite?.state === "sealed" && nearSite !== dismissedSite) {
1110	          openTerminal("review", nearSite);
1111	        } else if (atReportSpot && allAdded() && !reportSent && !reportDismissed) {
1112	          openTerminal("report", null);
1113	        }
1114	      } else if (termMode === "review" &&
1115	                 (nearSite !== reviewSite || reviewSite.state !== "sealed")) {
1116	        // walked away mid-review (ADD closes it itself)
1117	        if (nearSite !== reviewSite) closeTerminal(false);
1118	      } else if (termMode === "report" && !atReportSpot && !reportSent) {
1119	        closeTerminal(false);
1120	      }
1121	    }
1122	
1123	    overhead.update(t);
1124	    if (active) refreshHud();
1125	  }
1126	
1127	  // ---------- lifecycle ----------
1128	  function enter() {
1129	    active = true;
1130	    fp.groundAt(0, terrain.radius * 0.75);
1131	    camera.lookAt(CONSOLE_POS.x, terrain.heightAt(CONSOLE_POS.x, CONSOLE_POS.z) + 5, CONSOLE_POS.z);
1132	    canvas.addEventListener("click", onCanvasClick);
1133	    window.addEventListener("keydown", onKeyDown);
1134	    dbHud?.classList.remove("hidden");
1135	    fpShared?.classList.remove("hidden");
1136	    setControls(false);
1137	    crosshair?.classList.add("hidden");
1138	    updateSystems();
1139	    if (!started) {
1140	      showBriefing();
1141	    } else if (reportSent) {
1142	      fp.attach();
1143	      winEl?.classList.remove("hidden");
1144	    } else if (failed) {
1145	      resetLevel();                 // came back after a wipe → fresh run
1146	    } else {
1147	      fp.attach();
1148	      timerRunning = true;          // resume the level clock
1149	      showTutorial("The subagents kept working while you were in orbit.", 5000);
1150	    }
1151	    updateClock();
1152	    applyPanicSky();
1153	  }
1154	  function exit() {
1155	    active = false;
1156	    timerRunning = false;           // pause the clock while in orbit
1157	    setMap(false);
1158	    closeTerminal(false);
1159	    clearTimeout(winTimer);
1160	    fp.unlock();
1161	    fp.detach();
1162	    canvas.removeEventListener("click", onCanvasClick);
1163	    window.removeEventListener("keydown", onKeyDown);
1164	    setPrompt(null);
1165	    hideControls();
1166	    tutorialEl?.classList.add("hidden");
1167	    termEl?.classList.add("hidden");
1168	    failEl?.classList.add("hidden");
1169	    winEl?.classList.add("hidden");
1170	    briefingEl?.classList.add("hidden");
1171	    dbHud?.classList.add("hidden");
1172	    fpShared?.classList.add("hidden");
1173	    crosshair?.classList.add("hidden");
1174	  }
1175	  function resize() {
1176	    camera.aspect = window.innerWidth / window.innerHeight;
1177	    camera.updateProjectionMatrix();
1178	    overhead.resize();
1179	  }
1180	
1181	  return {
1182	    scene,
