1	import * as THREE from "three";
2	import { createTerrain } from "./terrain.js";
3	import { makeBeamTexture } from "./memoryProps.js";
4	import { SYSTEMS, UPGRADE_BUILDERS } from "./droneBayView.js";
5	
6	// LEVEL 3 ("Launch Clearance") — the finale. The ship is rebuilt; now it has
7	// to fly. The player sits in the pilot's chair for the first time, and the
8	// whole level happens at one console — no walking.
9	//
10	// The launch computer won't arm on work nobody can account for, and most of
11	// today's work the player never watched (the subagents did it). So the ship's
12	// AI — the amnesiac from Level 1, now running on the memory the player banked
13	// for it — asks five questions only the record can answer:
14	//
15	//   the ship asks in plain words            → you provably don't know
16	//   pick a way to look it up (1/2/3)        → command or skill, your call
17	//   it runs visibly, answers in its voice   → raw card vs. one plain sentence
18	//   pick the answer — it's on screen        → a launch-code segment locks
19	//   five segments → ignition → LIFTOFF      → the game's ending
20	//
21	// Menu rule: mostly ALL VALID (different lenses on the same truth), with the
22	// occasional polite dead end that costs only clock seconds and teaches the
23	// tool's boundary. Failure lives in the launch window, nowhere else.
24	
25	const TOTAL_TIME = 150;      // seconds of launch window (tunable)
26	const LOW_TIME = 45;         // clock turns urgent under this
27	const CRIT_TIME = 15;        // clock goes CRITICAL under this
28	const PANIC_TIME = 45;       // the SKY starts shifting toward panic-red
29	const NEXT_DELAY = 1.6;      // seconds between a confirm and the next question
30	const IGN_DUR = 3;           // seconds of 3-2-1 before ignition
31	const LIFT_DUR = 9;          // seconds of liftoff before the win screen
32	
33	// Sky palette — calm/panic as in L1/L2, plus the space we lift into.
34	const SKY_CALM  = new THREE.Color(0x2a2350);
35	const SKY_PANIC = new THREE.Color(0x6e0f16);
36	const FOG_PANIC = new THREE.Color(0x4a0a0e);
37	const DOME_CALM = new THREE.Color(0x3a3168);
38	const DOME_PANIC = new THREE.Color(0x7a141c);
39	const SUN_CALM  = new THREE.Color(0xfff1dc);
40	const SUN_PANIC = new THREE.Color(0xff5a3c);
41	const SKY_SPACE = new THREE.Color(0x040310);
42	const DOME_SPACE = new THREE.Color(0x070518);
43	
44	// Where the ship sits — the cockpit looks out over the island from here.
45	// Eye height node-verified: at 19 all five upgrades clear the dunes.
46	const RIG_POS = { x: -4, z: 66 };
47	const RIG_EYE = 19;
48	
49	// The full record Level 3 quizzes: Level 1's three banked memories (ids match
50	// the Archive's continuity touch) plus Level 2's five subagent repairs.
51	const L1_RECORD = [
52	  ["31f0cafe4d12", "recovered: abandoned EVA helmet"],
53	  ["7e11a2b09c44", "recovered: torn logbook page"],
54	  ["b0a7ded51a6e", "recovered: cracked nav panel"],
55	];
56	const RECORD_TOTAL = L1_RECORD.length + SYSTEMS.length; // 8
57	
58	// ---------- the five pre-flight questions ----------
59	// Each tool: label (what the menu shows), echo (what "runs" at the prompt),
60	// rows ([key, value] output lines), ok (false = dead end), note (the flash).
61	// `site` = which upgrade flares on confirm (index into SYSTEMS, or null).
62	function cardRows(sys) {
63	  return [["checkpoint", sys.ckpt], ...sys.card];
64	}
65	const ANTENNA = SYSTEMS[2], COILS = SYSTEMS[0], STRUTS = SYSTEMS[4];
66	
67	const QUESTIONS = [
68	  {
69	    q: "First check — the long-range antenna. The log says the rebuild wasn't simple. How many attempts did it take?",
70	    site: 2,
71	    tools: [
72	      {
73	        label: `entire checkpoint explain ${ANTENNA.ckpt}`,
74	        echo: `entire checkpoint explain ${ANTENNA.ckpt}`,
75	        ok: true, rows: cardRows(ANTENNA),
76	        note: "the raw record — the answer is in there",
77	      },
78	      {
79	        label: "Skill: what-happened — ask in plain language",
80	        echo: "what happened to the antenna?",
81	        ok: true, rows: [
82	          ["ran", `entire checkpoint explain ${ANTENNA.ckpt}`],
83	          ["answer", "subagent-3 respun the mast into a signal spire — it took 3 attempts; the first two fell over."],
84	        ],
85	        note: "the skill ran the command for you",
86	      },
87	      {
88	        label: "entire dispatch",
89	        echo: "entire dispatch",
90	        ok: false, rows: [
91	          ["DISPATCH", "day report — 5 systems repaired, 5 checkpoints filed"],
92	        ],
93	        note: "the day's report counts systems, not attempts — try another way",
94	      },
95	    ],
96	    answers: ["2", "3", "5"], correct: 1,
97	  },
98	  {
99	    q: "Something on this ship is built from salvaged hull plate. Which system?",
100	    site: 0,
101	    tools: [
102	      {
103	        label: `entire checkpoint search "hull plate"`,
