334	      pos[i] = cx; pos[i + 1] = cy; pos[i + 2] = cz;
335	      const v = new THREE.Vector3().randomDirection().multiplyScalar(9 + Math.random() * 15);
336	      b.vel[i] = v.x; b.vel[i + 1] = v.y; b.vel[i + 2] = v.z;
