618	    if (launched || won) {
619	      const k = Math.min(1, rig.position.y / 380);
620	      scene.background.copy(SKY_CALM).lerp(SKY_SPACE, k);
621	      scene.fog.color.copy(SKY_CALM).lerp(SKY_SPACE, k);
622	      dome.material.color.copy(DOME_CALM).lerp(DOME_SPACE, k);
623	      starMat.opacity = k;
624	      return;
625	    }
626	    const p = panicFactor();
627	    scene.background.copy(SKY_CALM).lerp(SKY_PANIC, p);
628	    scene.fog.color.copy(SKY_CALM).lerp(FOG_PANIC, p);
629	    dome.material.color.copy(DOME_CALM).lerp(DOME_PANIC, p);
630	    sun.color.copy(SUN_CALM).lerp(SUN_PANIC, p * 0.85);
631	  }
632	
633	  // ---------- briefing / win / fail / reset ----------
634	  function showBriefing() {
635	    timerRunning = false;
636	    briefingEl?.classList.remove("hidden");
637	    consoleEl?.classList.add("hidden");
638	  }
639	  function startLevel() {
640	    if (started) return;
641	    started = true;
642	    briefingEl?.classList.add("hidden");
643	    consoleEl?.classList.remove("hidden");
644	    timeLeft = TOTAL_TIME;
645	    timerRunning = true;
646	    updateClock();
647	    renderCode();
648	    renderQuestion();
649	  }
650	  briefingStartBtn?.addEventListener("click", startLevel);
651	
652	  function failLevel() {
653	    if (failed || launched) return;
654	    failed = true;
655	    timerRunning = false;
656	    clearTimeout(nextTimer);
657	    countdownEl?.classList.remove("is-low", "is-critical");
658	    consoleEl?.classList.add("hidden");
659	    failEl?.classList.remove("hidden");
660	  }
661	  function resetLevel() {
662	    failed = false;
663	    igniting = false;
664	    ignT = 0;
665	    ignTick = -1;
666	    launched = false;
667	    won = false;
668	    liftT = 0;
669	    burstTimer = 0;
670	    resetBursts();
671	    ignitionEl?.classList.add("hidden");
672	    flashEl?.classList.remove("show");
673	    qIndex = 0;
674	    phase = "menu";
675	    usedTool = null;
676	    deadTools = new Set();
677	    wrongChips = new Set();
678	    clearTimeout(nextTimer);
679	    for (const Q of QUESTIONS) Q.done = false;
680	    for (const s of sites) {
681	      s.confirmed = false;
682	      s.flareT = 0;
683	      s.beam.visible = false;
684	      s.beam.material.opacity = 0;
685	    }
686	    rig.position.y = rigGroundY + RIG_EYE;
687	    camera.rotation.x = baseRotX;
688	    camera.rotation.y = baseRotY;
689	    starMat.opacity = 0;
690	    sun.intensity = 1.5;
691	    scene.fog.far = 420;
692	    failEl?.classList.add("hidden");
693	    winEl?.classList.add("hidden");
694	    consoleEl?.classList.remove("hidden");
695	    timeLeft = TOTAL_TIME;
696	    timerRunning = true;
697	    updateClock();
698	    renderCode();
699	    renderQuestion();
700	  }
701	
702	  // ---------- input ----------
703	  function onKeyDown(e) {
704	    if (!active) return;
705	    if (!started) {
706	      if (e.code === "Enter" || e.code === "Space") { startLevel(); e.preventDefault(); }
707	      return;
708	    }
709	    if (failed) {
710	      if (e.code === "KeyR") { resetLevel(); e.preventDefault(); }
711	      return;
712	    }
713	    if (won || launched || igniting) {
714	      if (won && e.code === "KeyB") onExit?.();
715	      return;
716	    }
717	    if (phase === "single" && e.code === "Enter") { fileFlightLog(); e.preventDefault(); return; }
718	    if (e.key >= "1" && e.key <= "3") {
719	      const i = Number(e.key) - 1;
720	      if (phase === "menu") pickTool(i);
721	      else if (phase === "chips") pickChip(i);
722	      e.preventDefault();
723	      return;
724	    }
725	    if (e.code === "KeyB") onExit?.();
726	  }
727	  menuEl?.addEventListener("click", (e) => {
728	    if (!active || failed || launched) return;
729	    const btn = e.target.closest?.("[data-tool]");
730	    if (btn) pickTool(Number(btn.dataset.tool));
731	    else if (phase === "single" && e.target.closest?.(".lc-single, .lc-single-cta")) fileFlightLog();
732	  });
733	  answersEl?.addEventListener("click", (e) => {
734	    if (!active || failed || launched) return;
735	    const btn = e.target.closest?.("[data-chip]");
736	    if (btn) pickChip(Number(btn.dataset.chip));
737	  });
738	
739	  // ---------- per-frame ----------
740	  function update(dt, t) {
741	    if (active && timerRunning && started && !failed && !launched) {
742	      timeLeft = Math.max(0, timeLeft - dt);
743	      updateClock();
744	      if (timeLeft <= 0) failLevel();
745	    }
746	    applySky();
747	
748	    // The upgrades stay alive, exactly as Level 2 left them.
749	    for (const s of sites) {
750	      const anim = s.model.userData.anim;
751	      if (anim?.type === "ring") {
752	        anim.ring.rotation.y += dt * 0.8;
753	        anim.ring.position.y = 3.4 + Math.sin(t * 1.6) * 0.2;
754	      } else if (anim?.type === "dome") {
755	        anim.field.rotation.y += dt * 0.25;
756	        anim.orbit.rotation.z += dt * 0.6;
757	      } else if (anim?.type === "skid") {
758	        anim.pad.position.y = 1.6 + Math.sin(t * 1.8) * 0.25;
759	      }
760	      // Gold confirm flare: quick bloom, then settles to a steady glow —
761	      // and a full-power salute from every beam once the engines are lit.
762	      if (s.confirmed) {
763	        s.flareT += dt;
764	        const settle = 0.28 + Math.sin(t * 2.2 + s.idx) * 0.04;
765	        const bloom = Math.max(0, 1 - s.flareT / 2.5) * 0.5;
766	        const salute = (igniting || launched) ? 0.45 + Math.sin(t * 7 + s.idx) * 0.15 : 0;
767	        s.beam.material.opacity = Math.min(1, settle + bloom + salute);
768	      }
769	    }
770	
771	    if (igniting) {
772	      // 3… 2… 1… — the rumble builds with the count.
773	      ignT += dt;
774	      const tick = Math.floor(ignT);
775	      if (tick !== ignTick && tick < IGN_DUR) {
776	        ignTick = tick;
777	        setIgnitionText(String(IGN_DUR - tick), false);
778	      }
779	      const amp = 0.0015 + (ignT / IGN_DUR) * 0.006;
780	      camera.rotation.x = baseRotX + (Math.random() - 0.5) * amp;
781	      camera.rotation.y = baseRotY + (Math.random() - 0.5) * amp;
782	      if (ignT >= IGN_DUR) igniteNow();
783	    } else if (launched && !won) {
784	      // Liftoff: the island falls away, the sky becomes space, the island
785	      // cheers — fireworks streaming past the window.
786	      liftT += dt;
787	      const v = Math.min(46, 6 + liftT * 9);
788	      rig.position.y += v * dt;
789	      const rumble = Math.max(0, 1 - liftT / 3) * 0.006;
790	      camera.rotation.x = baseRotX - Math.min(0.5, liftT * 0.07) + (Math.random() - 0.5) * rumble;
791	      camera.rotation.y = baseRotY + (Math.random() - 0.5) * rumble;
792	      camera.rotation.z = Math.sin(t * 1.3) * 0.004;
793	      scene.fog.far = Math.min(2200, 420 + liftT * 320);
794	      sun.intensity = Math.max(0.6, 1.5 - liftT * 0.1);
795	      burstTimer -= dt;
796	      if (burstTimer <= 0 && liftT < LIFT_DUR - 1.5) {
797	        const idle = bursts.find((b) => !b.active);
798	        if (idle) fireBurst(idle);
799	        burstTimer = 0.45 + Math.random() * 0.5;
800	      }
801	      if (liftT >= LIFT_DUR) {
802	        won = true;
803	        if (winSub) winSub.textContent =
804	          `homeward — ${RECORD_TOTAL} checkpoints · ${QUESTIONS.length} questions · 0 guesses`;
805	        winEl?.classList.remove("hidden");
806	      }
807	    } else if (!failed && !won) {
808	      // Idle cockpit sway — alive, not nauseating.
809	      camera.rotation.x = baseRotX + Math.sin(t * 0.7) * 0.006;
810	      camera.rotation.y = baseRotY + Math.sin(t * 0.45) * 0.008;
811	    }
812	    updateBursts(dt);
813	  }
814	
815	  // ---------- lifecycle ----------
816	  function enter() {
817	    active = true;
818	    window.addEventListener("keydown", onKeyDown);
819	    hud?.classList.remove("hidden");
820	    if (!started) {
821	      showBriefing();
822	    } else if (won) {
823	      winEl?.classList.remove("hidden");
824	    } else if (failed) {
825	      resetLevel();                 // came back after a miss → fresh window
826	    } else if (!launched) {
827	      consoleEl?.classList.remove("hidden");
828	      timerRunning = true;          // resume the window clock
829	    }
830	    updateClock();
831	    renderCode();
832	    applySky();
833	  }
834	  function exit() {
835	    active = false;
836	    timerRunning = false;           // the window politely waits in orbit
837	    clearTimeout(nextTimer);
838	    window.removeEventListener("keydown", onKeyDown);
839	    hud?.classList.add("hidden");
840	    briefingEl?.classList.add("hidden");
841	    consoleEl?.classList.add("hidden");
842	    ignitionEl?.classList.add("hidden");
843	    flashEl?.classList.remove("show");
844	    winEl?.classList.add("hidden");
845	    failEl?.classList.add("hidden");
846	  }
847	  function resize() {
848	    camera.aspect = window.innerWidth / window.innerHeight;
849	    camera.updateProjectionMatrix();
850	  }
851	
852	  return { scene, camera, update, enter, exit, resize };
853	}
