import * as THREE from "three";

// Gradient sky dome for the island levels — replaces the flat-color sphere.
// A simple horizon→zenith blend on the inside of a big sphere; the levels
// drive the two uniforms every frame (calm ↔ panic ↔ space), exactly like
// they used to drive the old dome's single material color.
export function makeSkyDome(radius, { horizon, zenith } = {}) {
  const uniforms = {
    uHorizon: { value: (horizon ?? new THREE.Color(0x4a3f82)).clone() },
    uZenith: { value: (zenith ?? new THREE.Color(0x231c45)).clone() },
  };
  const mat = new THREE.ShaderMaterial({
    uniforms,
    vertexShader: /* glsl */ `
      varying vec3 vDir;
      void main() {
        vDir = normalize(position);
        gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
      }
    `,
    fragmentShader: /* glsl */ `
      varying vec3 vDir;
      uniform vec3 uHorizon;
      uniform vec3 uZenith;
      void main() {
        // Height above the horizon, eased so the warm band hugs the skyline
        // and the zenith settles early. Below the horizon, hold the band.
        float h = clamp(vDir.y, 0.0, 1.0);
        float k = pow(1.0 - h, 2.4);
        gl_FragColor = vec4(mix(uZenith, uHorizon, k), 1.0);
      }
    `,
    side: THREE.BackSide,
    depthWrite: false,
    fog: false,
  });
  const dome = new THREE.Mesh(new THREE.SphereGeometry(radius, 32, 16), mat);
  // Levels lerp the sky every frame; expose the uniforms where the old code
  // reached for dome.material.color.
  dome.userData.horizon = uniforms.uHorizon.value;
  dome.userData.zenith = uniforms.uZenith.value;
  return dome;
}

