import * as THREE from "three";

// Shadow-casting sun shared by the island levels. One ortho frustum sized to
// the whole walkable island, so every prop grounds itself with a real shadow.
export function makeIslandSun(color, intensity = 1.5) {
  const sun = new THREE.DirectionalLight(color, intensity);
  sun.position.set(60, 90, 40);
  sun.castShadow = true;
  sun.shadow.mapSize.set(2048, 2048);
  sun.shadow.camera.left = -130;
  sun.shadow.camera.right = 130;
  sun.shadow.camera.top = 130;
  sun.shadow.camera.bottom = -130;
  sun.shadow.camera.near = 10;
  sun.shadow.camera.far = 360;
  sun.shadow.bias = -0.0004;
  sun.shadow.normalBias = 0.5;
  return sun;
}

// Make every opaque mesh under root cast and receive shadows. Transparent
// work (beams, ice, sprites, glow) must not cast — additive glow throwing a
// solid black shadow reads as a bug, not a light.
export function castShadows(root) {
  root.traverse((n) => {
    if (n.isMesh && n.material && !n.material.transparent) {
      n.castShadow = true;
      n.receiveShadow = true;
    }
  });
  return root;
}

