function mix(a, b, t) {
  return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t, a[2] + (b[2] - a[2]) * t];
}
function ramp(t) {
  if (t < 0.18) return mix(C_DEEP, C_SHORE, t / 0.18);
  if (t < 0.5) return mix(C_SHORE, C_GOLD, (t - 0.18) / 0.32);
  return mix(C_GOLD, C_PEAK, Math.min(1, (t - 0.5) / 0.5));
}

input.new_string:
function mix(a, b, t) {
  return [a[0] + (b[0] - a[0]) * t, a[1] + (b[1] - a[1]) * t, a[2] + (b[2] - a[2]) * t];
}
function ramp(t) {
  if (t < 0.18) return mix(C_DEEP, C_SHORE, t / 0.18);
  if (t < 0.5) return mix(C_SHORE, C_GOLD, (t - 0.18) / 0.32);
  return mix(C_GOLD, C_PEAK, Math.min(1, (t - 0.5) / 0.5));
}

// ---- water ripple normal map ----
// A periodic sum-of-sines height field (integer wave vectors → tiles
// seamlessly under RepeatWrapping), baked once into a tangent-space normal
// map. The water animates by scrolling this texture's offset.
const WAVES = [
  { a: 1, b: 2, amp: 1.0, ph: 0.0 },
  { a: 3, b: 1, amp: 0.55, ph: 1.7 },
  { a: 2, b: -3, amp: 0.4, ph: 4.1 },
  { a: 4, b: 3, amp: 0.28, ph: 2.6 },
  { a: -2, b: 5, amp: 0.22, ph: 5.3 },
  { a: 5, b: -1, amp: 0.18, ph: 0.9 },
];
function makeWaterNormalTexture(size = 256) {
  const c = document.createElement("canvas");
  c.width = c.height = size;
  const ctx = c.getContext("2d");
  const img = ctx.createImageData(size, size);
  const d = img.data;
  const TAU = Math.PI * 2;
  const strength = 1.6; // slope exaggeration before normalization
  for (let y = 0; y < size; y++) {
    const v = y / size;
    for (let x = 0; x < size; x++) {
      const u = x / size;
      let du = 0, dv = 0;
      for (const w of WAVES) {
        const k = Math.cos(TAU * (w.a * u + w.b * v) + w.ph) * w.amp * TAU;
        du += k * w.a;
        dv += k * w.b;
      }
      const nx = -du * strength, ny = -dv * strength, nz = 14;
      const len = Math.hypot(nx, ny, nz);
      const i = (y * size + x) * 4;
      d[i] = ((nx / len) * 0.5 + 0.5) * 255;
      d[i + 1] = ((ny / len) * 0.5 + 0.5) * 255;
      d[i + 2] = ((nz / len) * 0.5 + 0.5) * 255;
      d[i + 3] = 255;
    }
  }
  ctx.putImageData(img, 0, 0);
  const t = new THREE.CanvasTexture(c);
  t.colorSpace = THREE.NoColorSpace;
  t.wrapS = t.wrapT = THREE.RepeatWrapping;
  return t;
}

// ---- terrain detail textures ----
// Vertex colors carry the palette; this adds close-up grain so the ground
// doesn't go mushy where the player actually walks. Mirrored wrapping hides
// the seams of the non-periodic noise.
function makeDetailTextures(seed, size = 256) {
  const noise = makeNoise3D(seed * 31 + 5);
  const fbm = makeFbm(noise, { octaves: 4, lacunarity: 2.2, gain: 0.55 });
  const heights = new Float32Array(size * size);
  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      heights[y * size + x] = fbm(x * 0.045, 0, y * 0.045) * 0.5 + 0.5;
    }
  }

  const color = document.createElement("canvas");
  color.width = color.height = size;
  const cImg = color.getContext("2d").createImageData(size, size);
  const normal = document.createElement("canvas");
  normal.width = normal.height = size;
  const nImg = normal.getContext("2d").createImageData(size, size);
  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const i = (y * size + x) * 4;
      const h = heights[y * size + x];
      // Subtle brightness grain: multiplies the vertex colors (≤1 factors).
      const g = 208 + h * 47;
      cImg.data[i] = cImg.data[i + 1] = cImg.data[i + 2] = g;
      cImg.data[i + 3] = 255;

      const hx = heights[y * size + Math.min(size - 1, x + 1)] - h;
      const hy = heights[Math.min(size - 1, y + 1) * size + x] - h;
      const nx = -hx * 6, ny = -hy * 6, nz = 1;
      const len = Math.hypot(nx, ny, nz);
      nImg.data[i] = ((nx / len) * 0.5 + 0.5) * 255;
      nImg.data[i + 1] = ((ny / len) * 0.5 + 0.5) * 255;
      nImg.data[i + 2] = ((nz / len) * 0.5 + 0.5) * 255;
      nImg.data[i + 3] = 255;
    }
  }
  color.getContext("2d").putImageData(cImg, 0, 0);
  normal.getContext("2d").putImageData(nImg, 0, 0);

  const wrap = (canvas, srgb) => {
    const t = new THREE.CanvasTexture(canvas);
    t.colorSpace = srgb ? THREE.SRGBColorSpace : THREE.NoColorSpace;
    t.wrapS = t.wrapT = THREE.MirroredRepeatWrapping;
    t.repeat.set(24, 24);
    t.anisotropy = 4;
    return t;
  };
  return { map: wrap(color, true), normalMap: wrap(normal, false) };
}

