      const i = (y * foamSize + x) * 4;
      fImg.data[i] = fImg.data[i + 1] = fImg.data[i + 2] = 255;
      fImg.data[i + 3] = Math.min(255, band * (0.25 + 0.75 * wob) * 235);
    }
  }
  foamCanvas.getContext("2d").putImageData(fImg, 0, 0);
  const foamTex = new THREE.CanvasTexture(foamCanvas);
  foamTex.colorSpace = THREE.SRGBColorSpace;
  const foam = new THREE.Mesh(
    new THREE.PlaneGeometry(size, size),
    new THREE.MeshBasicMaterial({
      map: foamTex, transparent: true, opacity: 0.55, depthWrite: false,
    })
  );
  foam.rotation.x = -Math.PI / 2;
  foam.position.y = seaLevel + 0.12;

