  // counter-rotation of the repeat origin would be overkill — two speeds on
  // one offset read as cross-chop already), foam breathes against the shore.
  function update(dt, t) {
    waterNormals.offset.x += dt * 0.018;
    waterNormals.offset.y += dt * 0.012;
    foam.material.opacity = 0.45 + 0.16 * (0.5 + 0.5 * Math.sin(t * 1.3));
