/**
 * Flat Saturn-style ring. Returns a mesh lying in the planet's equatorial
 * plane — add it to the planetGroup so it shares the axial tilt.
 */
export function makeRing(planetRadius, {
  inner = planetRadius * 1.35,
  outer = planetRadius * 2.25,
} = {}) {
  const geo = new THREE.RingGeometry(inner, outer, 256, 1);

  // Remap UVs so the texture runs radially (u = normalized radius), letting the
  // 1D band texture paint concentric bands instead of RingGeometry's default.
  const pos = geo.attributes.position;
  const uv = geo.attributes.uv;
  const v = new THREE.Vector3();
  for (let i = 0; i < pos.count; i++) {
    v.fromBufferAttribute(pos, i);
    const r = v.length();
    uv.setXY(i, (r - inner) / (outer - inner), 0.5);
  }
  uv.needsUpdate = true;

  const mat = new THREE.MeshBasicMaterial({
    map: makeRingTexture(),
    transparent: true,
    side: THREE.DoubleSide,
    depthWrite: false,
    opacity: 0.92,
  });

  const ring = new THREE.Mesh(geo, mat);
  ring.rotation.x = -Math.PI / 2; // lie flat in the equatorial plane
  return ring;
}

input.new_string:
/**
 * Flat Saturn-style ring. Returns a mesh lying in the planet's equatorial
 * plane — add it to the planetGroup so it shares the axial tilt.
 *
 * The fragment shader fakes the planet's shadow: any ring point on the far
 * side of the planet (relative to sunDir) and within the planet's silhouette
 * falls into a soft-edged eclipse wedge — the classic Saturn render detail.
 */
export function makeRing(planetRadius, {
  inner = planetRadius * 1.35,
  outer = planetRadius * 2.25,
  sunDir = new THREE.Vector3(5, 2.5, 4).normalize(),
} = {}) {
  const geo = new THREE.RingGeometry(inner, outer, 256, 1);

  // Remap UVs so the texture runs radially (u = normalized radius), letting the
  // 1D band texture paint concentric bands instead of RingGeometry's default.
  const pos = geo.attributes.position;
  const uv = geo.attributes.uv;
  const v = new THREE.Vector3();
  for (let i = 0; i < pos.count; i++) {
    v.fromBufferAttribute(pos, i);
    const r = v.length();
    uv.setXY(i, (r - inner) / (outer - inner), 0.5);
  }
  uv.needsUpdate = true;

  const mat = new THREE.ShaderMaterial({
    uniforms: {
      map: { value: makeRingTexture() },
      sunDir: { value: sunDir.clone().normalize() }, // world space; planet at origin
      planetRadius: { value: planetRadius },
      opacity: { value: 0.92 },
    },
    vertexShader: /* glsl */ `
      varying vec2 vUv;
      varying vec3 vWorld;
      void main() {
        vUv = uv;
        vWorld = (modelMatrix * vec4(position, 1.0)).xyz;
        gl_Position = projectionMatrix * viewMatrix * vec4(vWorld, 1.0);
      }
    `,
    fragmentShader: /* glsl */ `
      varying vec2 vUv;
      varying vec3 vWorld;
      uniform sampler2D map;
      uniform vec3 sunDir;
      uniform float planetRadius;
      uniform float opacity;
      void main() {
        vec4 c = texture2D(map, vUv);
        // Project onto the sun axis: behind the planet and inside its
        // silhouette → eclipsed, with a soft penumbra at the edge.
        float b = dot(vWorld, sunDir);
        float d = length(vWorld - b * sunDir);
        float lit = b > 0.0
          ? 1.0
          : smoothstep(planetRadius * 0.96, planetRadius * 1.22, d);
        c.rgb *= mix(0.16, 1.0, lit);
        gl_FragColor = vec4(c.rgb, c.a * opacity);
      }
    `,
    transparent: true,
    side: THREE.DoubleSide,
    depthWrite: false,
  });

  const ring = new THREE.Mesh(geo, mat);
  ring.rotation.x = -Math.PI / 2; // lie flat in the equatorial plane
  return ring;
}

