import { chromium } from "playwright";

const SHOTS = [
  { name: "orbit", url: "http://127.0.0.1:5173/", wait: 6000 },
  { name: "island", url: "http://127.0.0.1:5173/?view=island", wait: 6000 },
  { name: "level2", url: "http://127.0.0.1:5173/?view=level2", wait: 6000 },
  { name: "level3", url: "http://127.0.0.1:5173/?view=level3", wait: 6000 },
];

const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });

const errors = [];
page.on("console", (msg) => {
  if (msg.type() === "error") errors.push(`[console] ${msg.text()}`);
});
page.on("pageerror", (err) => errors.push(`[pageerror] ${err.message}`));

for (const shot of SHOTS) {
  errors.length = 0;
  await page.goto(shot.url, { waitUntil: "load" });
  await page.waitForTimeout(shot.wait);
  await page.screenshot({ path: `/tmp/planetfall-shots/${shot.name}.png` });
  console.log(`${shot.name}: ${errors.length ? "ERRORS:\n" + errors.join("\n") : "no console errors"}`);
}

// Level 3 again, but start the level and file through to the console being up
await page.goto("http://127.0.0.1:5173/?view=level3", { waitUntil: "load" });
await page.waitForTimeout(4000);
await page.keyboard.press("Enter"); // dismiss briefing → console
await page.waitForTimeout(2500);
await page.screenshot({ path: "/tmp/planetfall-shots/level3-started.png" });
console.log("level3-started: done");

await browser.close();

