const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });
page.on("pageerror", (err) => console.log(`[pageerror] ${err.message}`));

// Island, in-world, after bloom retune
await page.goto("http://127.0.0.1:5173/?view=island", { waitUntil: "load" });
await page.waitForTimeout(4000);
await page.keyboard.press("Enter");
await page.waitForTimeout(1500);
await page.screenshot({ path: "/tmp/planetfall-shots/island-tuned.png" });
console.log("island-tuned");

// Drone bay: walk forward toward the island center where props live, then a
// tight clip on the center of frame to inspect shadows at full resolution.
await page.goto("http://127.0.0.1:5173/?view=level2", { waitUntil: "load" });
await page.waitForTimeout(4000);
await page.keyboard.press("Enter");
await page.waitForTimeout(800);
await page.keyboard.down("ArrowUp");
await page.waitForTimeout(4200);
await page.keyboard.up("ArrowUp");
await page.waitForTimeout(600);
await page.screenshot({ path: "/tmp/planetfall-shots/level2-tuned.png" });
await page.screenshot({
  path: "/tmp/planetfall-shots/level2-closeup.png",
  clip: { x: 340, y: 250, width: 600, height: 420 },
});
console.log("level2-tuned + closeup");

// Orbit after retune
await page.goto("http://127.0.0.1:5173/", { waitUntil: "load" });
await page.waitForTimeout(6000);
await page.screenshot({ path: "/tmp/planetfall-shots/orbit-tuned.png" });
console.log("orbit-tuned");

await browser.close();

