cd /tmp/planetfall-shots && cat > shoot4.mjs <<'EOF'
import { chromium } from "playwright";
const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });
page.on("pageerror", (err) => console.log(`[pageerror] ${err.message}`));
await page.goto("http://127.0.0.1:5173/?view=island", { waitUntil: "load" });
await page.waitForTimeout(4000);
await page.keyboard.press("Enter");
await page.waitForTimeout(800);
await page.keyboard.press("KeyM");
await page.waitForTimeout(1000);
await page.screenshot({ path: "/tmp/planetfall-shots/island-map.png" });
// crop around one artifact: map shows island ~centered; artifact at (-34,-28) world.
await page.screenshot({ path: "/tmp/planetfall-shots/island-map-crop.png",
  clip: { x: 380, y: 180, width: 420, height: 320 } });
console.log("island-map done");
await browser.close();
EOF
node shoot4.mjs

cd /tmp/planetfall-shots && cat > shoot5.mjs <<'EOF'
import { chromium } from "playwright";
const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1280, height: 800 } });
const errors = [];
page.on("console", (m) => { if (m.type() === "error") errors.push(m.text()); });
page.on("pageerror", (e) => errors.push(e.message));
await page.goto("http://127.0.0.1:5173/?view=archive", { waitUntil: "load" });
await page.waitForTimeout(5000);
await page.screenshot({ path: "/tmp/planetfall-shots/archive.png" });
console.log(errors.length ? "ERRORS:\n" + errors.join("\n") : "archive: no console errors");
await browser.close();
EOF
node shoot5.mjs
